export function createClaimSet() {
    return new Set();
}
export function posKey(p) {
    return `${p.x},${p.y}`;
}
export function claim(set, p) {
    set.add(posKey(p));
}
export function isClaimed(set, p) {
    return set.has(posKey(p));
}
export function createTickEvents() {
    return {
        murphyDied: false,
        levelWon: false,
        destroyedOccupantIds: new Set(),
        electronBursts: [],
    };
}
